#define MSG_RMDIR       12
#define MSG_CHDIR       13
#define MSG_STAT        14
#define MSG_SYNC        15
#define MSG_SHUTDOWN    16

/*
 * 32-byte IPC message structure.
 * On 64-bit systems: 4 ints (16 bytes) + 2 pointers (16 bytes) = 32 bytes.
 */
struct yfs_msg {
    int   type;    /* message type */
    int   arg1;    /* first integer arg / return value */
    int   arg2;    /* second integer arg */
    int   arg3;    /* third integer arg */
    void *ptr1;    /* first pointer arg */
    void *ptr2;    /* second pointer arg */
};

int
Open(char *path)
{
    struct yfs_msg msg;
    msg.type = MSG_OPEN;
    msg.arg1 = 0;
    msg.arg2 = 0;
    msg.arg3 = 0;
    msg.ptr1 = path;
    msg.ptr2 = (void *)0;
    Send(&msg, -FILE_SERVER);
    return msg.arg1;
}

int
Close(int fd)
{
    struct yfs_msg msg;
    msg.type = MSG_CLOSE;
    msg.arg1 = fd;
    msg.arg2 = 0;
    msg.arg3 = 0;
    msg.ptr1 = (void *)0;
    msg.ptr2 = (void *)0;
    Send(&msg, -FILE_SERVER);
    return msg.arg1;
}

