/*
 * yfs.c - Yalnix File System Server
 *
 * Implements a Unix-style file system on the Yalnix disk hardware.
 * Communicates with client processes via Yalnix IPC.
 */

#include <comp421/yalnix.h>
#include <comp421/filesystem.h>
#include <string.h>
#include <stdlib.h>
#include <stdio.h>

/* ============================================================
 * Message protocol (must match iolib.c)
 * ============================================================ */

#define MSG_OPEN        1
#define MSG_CLOSE       2
#define MSG_CREATE      3
#define MSG_READ        4
#define MSG_WRITE       5
#define MSG_SEEK        6
#define MSG_LINK        7
#define MSG_UNLINK      8
#define MSG_SYMLINK     9
#define MSG_READLINK    10
#define MSG_MKDIR       11
#define MSG_RMDIR       12
#define MSG_CHDIR       13
#define MSG_STAT        14
#define MSG_SYNC        15
#define MSG_SHUTDOWN    16

struct yfs_msg {
    int   type;
    int   arg1;
    int   arg2;
    int   arg3;
    void *ptr1;
    void *ptr2;
};

/* ============================================================
 * Constants
 * ============================================================ */

#define INODES_PER_BLOCK  (SECTORSIZE / INODESIZE)        /* 8 */
#define PTRS_PER_BLOCK    (SECTORSIZE / (int)sizeof(int)) /* 128 */
#define MAX_FILE_BLOCKS   (NUM_DIRECT + PTRS_PER_BLOCK)   /* 140 */
#define MAX_OPEN_TOTAL    512  /* max total open files across all processes */
#define MAX_CLIENTS       128  /* max simultaneous client processes */

/* ============================================================
 * Global filesystem state
 * ============================================================ */

static int g_num_blocks;        /* total blocks on disk */
static int g_num_inodes;        /* total inodes */
static int g_first_data_block;  /* block number of first data block */

/* ============================================================
 * Block cache (LRU)
 * ============================================================ */

static struct {
    int  valid;
    int  dirty;
    int  block_num;
    int  lru_time;
    char data[SECTORSIZE];
} bcache[BLOCK_CACHESIZE];

/* ============================================================
 * Inode cache (LRU)
 * ============================================================ */

static struct {
    int         valid;
    int         dirty;
    int         inum;
    int         lru_time;
    struct inode inode;
} icache[INODE_CACHESIZE];

static int g_lru_clock = 0;

/* ============================================================
 * Free block list (in-memory stack)
 * ============================================================ */

static int *g_free_blocks;
static int  g_free_block_count;

/* ============================================================
 * Free inode list (in-memory stack)
 * ============================================================ */

static int *g_free_inodes;
static int  g_free_inode_count;

/* ============================================================
 * Open file table
 * ============================================================ */

struct open_entry {
    int in_use;
    int pid;
    int fd;
    int inum;
    int reuse;
    int pos;
};

static struct open_entry g_open_table[MAX_OPEN_TOTAL];

/* ============================================================
 * Per-client state (cwd)
 * ============================================================ */

struct client_entry {
    int pid;
    int cwd_inum;
};

static struct client_entry g_clients[MAX_CLIENTS];
static int g_num_clients = 0;

/* ============================================================
 * Forward declarations
 * ============================================================ */

static void        sync_all(void);
static char       *get_block(int block_num);
static void        mark_block_dirty(int block_num);
static struct inode *get_inode(int inum);
static void        mark_inode_dirty(int inum);
static void        flush_inode(int inum);
static int         alloc_block(void);
static void        free_block(int block_num);
static int         alloc_inode(int type);
static void        free_inode_and_blocks(int inum);
static int         get_file_block(struct inode *inode, int inum, int block_idx, int create);
static int         file_read_data(int inum, int pos, char *buf, int len);
static int         file_write_data(int inum, int pos, const char *buf, int len);
static void        file_truncate(int inum);
static int         dir_lookup(int dir_inum, const char *name, int namelen, int *entry_offset);
static int         dir_add_entry(int dir_inum, const char *name, int namelen, int entry_inum);
static int         dir_remove_entry(int dir_inum, const char *name, int namelen);
static int         dir_is_empty(int dir_inum);
static int         resolve_path(const char *pathname, int cwd_inum, int follow_last,
                                int *parent_inum_out, char name_out[]);
static int         resolve_path_sym(const char *pathname, int cwd_inum, int follow_last,
                                    int *parent_inum_out, char name_out[], int depth);
static int         get_client_cwd(int pid);
static void        set_client_cwd(int pid, int cwd_inum);
static int         alloc_fd(int pid, int inum, int reuse);
static int         find_open(int pid, int fd);
static void        close_fd(int pid, int fd);

/* ============================================================
 * Block cache operations
 * ============================================================ */

static char *
get_block(int block_num)
{
    int i, oldest_idx, oldest_time;

    /* Search cache */
    for (i = 0; i < BLOCK_CACHESIZE; i++) {
        if (bcache[i].valid && bcache[i].block_num == block_num) {
            bcache[i].lru_time = ++g_lru_clock;
            return bcache[i].data;
        }
    }

    /* Find slot to evict (LRU) */
    oldest_idx = 0;
    oldest_time = bcache[0].valid ? bcache[0].lru_time : -1;
    for (i = 1; i < BLOCK_CACHESIZE; i++) {
        if (!bcache[i].valid) {
            oldest_idx = i;
            oldest_time = -1;
            break;
        }
        if (bcache[i].lru_time < oldest_time) {
            oldest_time = bcache[i].lru_time;
            oldest_idx = i;
        }
    }

    /* Write back dirty block if evicting */
    if (bcache[oldest_idx].valid && bcache[oldest_idx].dirty) {
        WriteSector(bcache[oldest_idx].block_num, bcache[oldest_idx].data);
        bcache[oldest_idx].dirty = 0;
    }

    /* Load new block */
    if (ReadSector(block_num, bcache[oldest_idx].data) != 0) {
        return NULL;
    }
    bcache[oldest_idx].valid = 1;
    bcache[oldest_idx].dirty = 0;
    bcache[oldest_idx].block_num = block_num;
    bcache[oldest_idx].lru_time = ++g_lru_clock;
    return bcache[oldest_idx].data;
}

static void
mark_block_dirty(int block_num)
{
    int i;
    for (i = 0; i < BLOCK_CACHESIZE; i++) {
        if (bcache[i].valid && bcache[i].block_num == block_num) {
            bcache[i].dirty = 1;
            return;
        }
    }
}

/* ============================================================
 * Inode cache operations
 * ============================================================ */

static struct inode *
get_inode(int inum)
{
    int i, oldest_idx, oldest_time;
    int inode_block_num, inode_off;
    char *blk;

    if (inum <= 0 || inum > g_num_inodes)
        return NULL;

    /* Search cache */
    for (i = 0; i < INODE_CACHESIZE; i++) {
        if (icache[i].valid && icache[i].inum == inum) {
            icache[i].lru_time = ++g_lru_clock;
            return &icache[i].inode;
        }
    }

    /* Find slot to evict (LRU) */
    oldest_idx = 0;
    oldest_time = icache[0].valid ? icache[0].lru_time : -1;
    for (i = 1; i < INODE_CACHESIZE; i++) {
        if (!icache[i].valid) {
            oldest_idx = i;
            oldest_time = -1;
            break;
        }
        if (icache[i].lru_time < oldest_time) {
            oldest_time = icache[i].lru_time;
            oldest_idx = i;
        }
    }

    /* Write back dirty inode if evicting */
    if (icache[oldest_idx].valid && icache[oldest_idx].dirty) {
        flush_inode(icache[oldest_idx].inum);
    }

    /* Load new inode from disk */
    inode_block_num = 1 + inum / INODES_PER_BLOCK;
    inode_off = (inum % INODES_PER_BLOCK) * INODESIZE;

    blk = get_block(inode_block_num);
    if (!blk)
        return NULL;

    memcpy(&icache[oldest_idx].inode, blk + inode_off, INODESIZE);
    icache[oldest_idx].valid = 1;
    icache[oldest_idx].dirty = 0;
    icache[oldest_idx].inum = inum;
    icache[oldest_idx].lru_time = ++g_lru_clock;
    return &icache[oldest_idx].inode;
}

static void
mark_inode_dirty(int inum)
{
    int i;
    for (i = 0; i < INODE_CACHESIZE; i++) {
        if (icache[i].valid && icache[i].inum == inum) {
            icache[i].dirty = 1;
            return;
        }
    }
}

static void
flush_inode(int inum)
{
    int i;
    int inode_block_num, inode_off;
    char *blk;

    for (i = 0; i < INODE_CACHESIZE; i++) {
        if (icache[i].valid && icache[i].inum == inum) {
            if (!icache[i].dirty)
                return;
            inode_block_num = 1 + inum / INODES_PER_BLOCK;
            inode_off = (inum % INODES_PER_BLOCK) * INODESIZE;
            blk = get_block(inode_block_num);
            if (blk) {
                memcpy(blk + inode_off, &icache[i].inode, INODESIZE);
                mark_block_dirty(inode_block_num);
            }
            icache[i].dirty = 0;
            return;
        }
    }
}

/* ============================================================
 * Sync: flush all dirty data
 * ============================================================ */

static void
sync_all(void)
{
    int i;

    /* Flush dirty inodes first */
    for (i = 0; i < INODE_CACHESIZE; i++) {
        if (icache[i].valid && icache[i].dirty) {
            flush_inode(icache[i].inum);
        }
    }

    /* Flush dirty blocks */
    for (i = 0; i < BLOCK_CACHESIZE; i++) {
        if (bcache[i].valid && bcache[i].dirty) {
            WriteSector(bcache[i].block_num, bcache[i].data);
            bcache[i].dirty = 0;
        }
    }
}

/* ============================================================
 * Block allocation
 * ============================================================ */

static int
alloc_block(void)
{
    int block_num;
    char *blk;

    if (g_free_block_count <= 0)
        return 0; /* disk full */

    block_num = g_free_blocks[--g_free_block_count];

    /* Zero out the new block */
    blk = get_block(block_num);
    if (blk) {
        memset(blk, 0, SECTORSIZE);
        mark_block_dirty(block_num);
    }
    return block_num;
}

static void
free_block(int block_num)
{
    if (block_num <= 0 || block_num < g_first_data_block || block_num >= g_num_blocks)
        return;
    g_free_blocks[g_free_block_count++] = block_num;
}

/* ============================================================
 * Inode allocation
 * ============================================================ */

static int
alloc_inode(int type)
{
    int inum;
    struct inode *inode;

    if (g_free_inode_count <= 0)
        return ERROR; /* no free inodes */

    inum = g_free_inodes[--g_free_inode_count];

    inode = get_inode(inum);
    if (!inode)
        return ERROR;

    /* Initialize the inode */
    inode->type = (short)type;
    inode->nlink = 0;
    inode->reuse++;
    inode->size = 0;
    memset(inode->direct, 0, sizeof(inode->direct));
    inode->indirect = 0;
    mark_inode_dirty(inum);

    return inum;
}

static void
free_inode_and_blocks(int inum)
{
    int i;
    struct inode *inode;
    char *ind_blk;
    int *ind_entries;

    inode = get_inode(inum);
    if (!inode)
        return;

    /* Free all direct blocks */
    for (i = 0; i < NUM_DIRECT; i++) {
        if (inode->direct[i] != 0) {
            free_block(inode->direct[i]);
            inode->direct[i] = 0;
        }
    }

    /* Free indirect blocks */
    if (inode->indirect != 0) {
        ind_blk = get_block(inode->indirect);
        if (ind_blk) {
            ind_entries = (int *)ind_blk;
            for (i = 0; i < PTRS_PER_BLOCK; i++) {
                if (ind_entries[i] != 0) {
                    free_block(ind_entries[i]);
                }
            }
        }
        free_block(inode->indirect);
        inode->indirect = 0;
    }

    /* Mark inode as free */
    inode->type = INODE_FREE;
    inode->nlink = 0;
    inode->size = 0;
    mark_inode_dirty(inum);

    /* Return to free list */
    g_free_inodes[g_free_inode_count++] = inum;
}

/* ============================================================
 * File block mapping
 * ============================================================ */

/*
 * Get the disk block number for block_idx-th block of a file.
 * If create=1 and the block doesn't exist, allocate it.
 * Returns block number (0 = hole/unallocated), or -1 on error.
 */
static int
get_file_block(struct inode *inode, int inum, int block_idx, int create)
{
    char *ind_blk;
    int *ind_entries;
    int new_block;
    int indirect_idx;

    if (block_idx < NUM_DIRECT) {
        if (inode->direct[block_idx] == 0 && create) {
            new_block = alloc_block();
            if (new_block == 0)
                return -1; /* disk full */
            inode->direct[block_idx] = new_block;
            mark_inode_dirty(inum);
        }
        return inode->direct[block_idx];
    }

    /* Indirect block */
    indirect_idx = block_idx - NUM_DIRECT;
    if (indirect_idx >= PTRS_PER_BLOCK)
        return -1; /* beyond max file size */

    if (inode->indirect == 0) {
        if (!create)
            return 0;
        new_block = alloc_block();
        if (new_block == 0)
            return -1;
        inode->indirect = new_block;
        mark_inode_dirty(inum);
        /* block is already zeroed by alloc_block */
    }

    ind_blk = get_block(inode->indirect);
    if (!ind_blk)
        return -1;

    ind_entries = (int *)ind_blk;
    if (ind_entries[indirect_idx] == 0 && create) {
        new_block = alloc_block();
        if (new_block == 0)
            return -1;
        ind_entries[indirect_idx] = new_block;
        mark_block_dirty(inode->indirect);
    }
    return ind_entries[indirect_idx];
}

/* ============================================================
 * File I/O
 * ============================================================ */

static int
file_read_data(int inum, int pos, char *buf, int len)
{
    struct inode *inode;
    int total_read, block_idx, block_off, block_num, chunk;
    char *blk;

    inode = get_inode(inum);
    if (!inode)
        return ERROR;

    if (pos >= inode->size || len <= 0)
        return 0;

    if (pos + len > inode->size)
        len = inode->size - pos;

    total_read = 0;
    while (len > 0) {
        block_idx = pos / BLOCKSIZE;
        block_off = pos % BLOCKSIZE;
        chunk = BLOCKSIZE - block_off;
        if (chunk > len)
            chunk = len;

        /* Need to re-fetch inode since get_block might evict it */
        inode = get_inode(inum);
        if (!inode)
            return ERROR;

        block_num = get_file_block(inode, inum, block_idx, 0);
        if (block_num == -1)
            return ERROR;

        if (block_num == 0) {
            /* Hole: return zeros */
            memset(buf + total_read, 0, chunk);
        } else {
            blk = get_block(block_num);
            if (!blk)
                return ERROR;
            memcpy(buf + total_read, blk + block_off, chunk);
        }

        total_read += chunk;
        pos += chunk;
        len -= chunk;
    }
    return total_read;
}

static int
file_write_data(int inum, int pos, const char *buf, int len)
{
    struct inode *inode;
    int total_written, block_idx, block_off, block_num, chunk;
    char *blk;

    if (len <= 0)
        return 0;

    total_written = 0;
    while (len > 0) {
        block_idx = pos / BLOCKSIZE;
        block_off = pos % BLOCKSIZE;
        chunk = BLOCKSIZE - block_off;
        if (chunk > len)
            chunk = len;

        /* Fetch inode fresh each iteration (cache evictions) */
        inode = get_inode(inum);
        if (!inode)
            return ERROR;

        block_num = get_file_block(inode, inum, block_idx, 1);
        if (block_num <= 0)
            return ERROR;

        blk = get_block(block_num);
        if (!blk)
            return ERROR;
        memcpy(blk + block_off, buf + total_written, chunk);
        mark_block_dirty(block_num);

        total_written += chunk;
        pos += chunk;
        len -= chunk;

        /* Update file size */
        inode = get_inode(inum);
        if (!inode)
            return ERROR;
        if (pos > inode->size) {
            inode->size = pos;
            mark_inode_dirty(inum);
        }
    }
    return total_written;
}

/*
 * Zero out blocks in range [pos, size) to handle holes when seeking past EOF.
 * Not strictly needed since holes naturally return zeros, but for gaps
 * that require explicit zeroing (seek past EOF then write), we rely on
 * alloc_block() zeroing new blocks.
 */
static void
file_truncate(int inum)
{
    struct inode *inode;
    int i;
    char *ind_blk;
    int *ind_entries;

    inode = get_inode(inum);
    if (!inode)
        return;

    /* Free all direct blocks */
    for (i = 0; i < NUM_DIRECT; i++) {
        if (inode->direct[i] != 0) {
            free_block(inode->direct[i]);
            inode->direct[i] = 0;
        }
    }

    /* Free indirect blocks */
    if (inode->indirect != 0) {
        ind_blk = get_block(inode->indirect);
        if (ind_blk) {
            ind_entries = (int *)ind_blk;
            for (i = 0; i < PTRS_PER_BLOCK; i++) {
                if (ind_entries[i] != 0) {
                    free_block(ind_entries[i]);
                    ind_entries[i] = 0;
                }
            }
        }
        free_block(inode->indirect);
        inode->indirect = 0;
    }

    inode = get_inode(inum);
    if (inode) {
        inode->size = 0;
        mark_inode_dirty(inum);
    }
}

/* ============================================================
 * Directory operations
 * ============================================================ */

/*
 * Look up a name in a directory.
 * Returns the inum of the entry, or 0 if not found, or ERROR on error.
 * If entry_offset is non-NULL, sets it to the byte offset in the directory.
 */
static int
dir_lookup(int dir_inum, const char *name, int namelen, int *entry_offset)
{
    struct inode *inode;
    struct dir_entry entry;
    int pos, n;

    if (namelen <= 0 || namelen > DIRNAMELEN)
        return 0;

    inode = get_inode(dir_inum);
    if (!inode || inode->type != INODE_DIRECTORY)
        return ERROR;

    pos = 0;
    while (pos < inode->size) {
        n = file_read_data(dir_inum, pos, (char *)&entry, sizeof(entry));
        if (n != (int)sizeof(entry))
            break;

        if (entry.inum != 0) {
            int cmplen = namelen < DIRNAMELEN ? namelen : DIRNAMELEN;
            if (memcmp(entry.name, name, cmplen) == 0) {
                /* Check that the rest is zero (or name fills DIRNAMELEN) */
                int ok = 1;
                if (namelen < DIRNAMELEN && entry.name[namelen] != '\0')
                    ok = 0;
                if (ok) {
                    if (entry_offset)
                        *entry_offset = pos;
                    return entry.inum;
                }
            }
        }
        pos += sizeof(entry);
    }
    return 0;
}

/*
 * Add a directory entry to a directory.
 * Reuses a free entry if available; otherwise appends.
 * Returns 0 on success, ERROR on failure.
 */
static int
dir_add_entry(int dir_inum, const char *name, int namelen, int entry_inum)
{
    struct inode *inode;
    struct dir_entry entry;
    int pos, n, free_pos;

    if (namelen <= 0 || namelen > DIRNAMELEN)
        return ERROR;

    inode = get_inode(dir_inum);
    if (!inode || inode->type != INODE_DIRECTORY)
        return ERROR;

    /* First pass: find a free slot */
    free_pos = -1;
    pos = 0;
    while (pos < inode->size) {
        n = file_read_data(dir_inum, pos, (char *)&entry, sizeof(entry));
        if (n != (int)sizeof(entry))
            break;
        if (entry.inum == 0 && free_pos < 0) {
            free_pos = pos;
            break;
        }
        pos += sizeof(entry);
    }

    /* Build entry */
    memset(&entry, 0, sizeof(entry));
    entry.inum = (short)entry_inum;
    memcpy(entry.name, name, namelen);

    if (free_pos >= 0) {
        /* Reuse free slot */
        if (file_write_data(dir_inum, free_pos, (char *)&entry, sizeof(entry)) < 0)
            return ERROR;
    } else {
        /* Append at end */
        inode = get_inode(dir_inum);
        if (!inode)
            return ERROR;
        pos = inode->size;
        if (file_write_data(dir_inum, pos, (char *)&entry, sizeof(entry)) < 0)
            return ERROR;
    }
    return 0;
}

/*
 * Remove a directory entry (set inum to 0).
 * Returns 0 on success, ERROR if not found.
 */
static int
dir_remove_entry(int dir_inum, const char *name, int namelen)
{
    struct inode *inode;
    struct dir_entry entry;
    int pos, n;

    if (namelen <= 0 || namelen > DIRNAMELEN)
        return ERROR;

    inode = get_inode(dir_inum);
    if (!inode || inode->type != INODE_DIRECTORY)
        return ERROR;

    pos = 0;
    while (pos < inode->size) {
        n = file_read_data(dir_inum, pos, (char *)&entry, sizeof(entry));
        if (n != (int)sizeof(entry))
            break;

        if (entry.inum != 0) {
            int cmplen = namelen < DIRNAMELEN ? namelen : DIRNAMELEN;
            if (memcmp(entry.name, name, cmplen) == 0) {
                int ok = 1;
                if (namelen < DIRNAMELEN && entry.name[namelen] != '\0')
                    ok = 0;
                if (ok) {
                    entry.inum = 0;
                    memset(entry.name, 0, DIRNAMELEN);
                    if (file_write_data(dir_inum, pos, (char *)&entry, sizeof(entry)) < 0)
                        return ERROR;
                    return 0;
                }
            }
        }
        pos += sizeof(entry);
    }
    return ERROR;
}

/*
 * Check if a directory is empty (only '.' and '..' entries, or free entries).
 * Returns 1 if empty, 0 if not empty, ERROR on error.
 */
static int
dir_is_empty(int dir_inum)
{
    struct inode *inode;
    struct dir_entry entry;
    int pos, n;

    inode = get_inode(dir_inum);
    if (!inode || inode->type != INODE_DIRECTORY)
        return ERROR;

    pos = 0;
    while (pos < inode->size) {
        n = file_read_data(dir_inum, pos, (char *)&entry, sizeof(entry));
        if (n != (int)sizeof(entry))
            break;

        if (entry.inum != 0) {
            /* Check for . and .. */
            if (entry.name[0] == '.' && entry.name[1] == '\0')
                goto next;
            if (entry.name[0] == '.' && entry.name[1] == '.' && entry.name[2] == '\0')
                goto next;
            return 0; /* non-empty */
        }
next:
        pos += sizeof(entry);
    }
    return 1;
}

/* ============================================================
 * Pathname resolution
 * ============================================================ */

static int
resolve_path_sym(const char *pathname, int cwd_inum, int follow_last,
                 int *parent_inum_out, char name_out[], int depth)
{
    char path_buf[MAXPATHNAMELEN + 1];
    char *comp, *next_sep;
    int cur_inum, next_inum, parent_inum, namelen;
    struct inode *inode;
    char symlink_buf[MAXPATHNAMELEN + 1];
    int symlink_len;

    if (depth > MAXSYMLINKS)
        return ERROR;

    if (!pathname || pathname[0] == '\0')
        return ERROR;

    if ((int)strlen(pathname) >= MAXPATHNAMELEN)
        return ERROR;

    strncpy(path_buf, pathname, MAXPATHNAMELEN);
    path_buf[MAXPATHNAMELEN] = '\0';

    /* Determine starting inode */
    if (path_buf[0] == '/') {
        cur_inum = ROOTINODE;
        comp = path_buf + 1;
    } else {
        cur_inum = cwd_inum;
        comp = path_buf;
    }

    parent_inum = cur_inum;

    /* Handle trailing slash: treat "/" as root directory */
    if (*comp == '\0') {
        /* Path is just "/" or was "/" */
        if (parent_inum_out)
            *parent_inum_out = cur_inum;
        if (name_out)
            name_out[0] = '\0';
        return cur_inum;
    }

    while (*comp != '\0') {
        /* Skip multiple slashes */
        while (*comp == '/')
            comp++;
        if (*comp == '\0')
            break;

        /* Find end of this component */
        next_sep = comp;
        while (*next_sep != '\0' && *next_sep != '/')
            next_sep++;

        namelen = (int)(next_sep - comp);
        if (namelen > DIRNAMELEN)
            return ERROR; /* component too long */

        int is_last = (*next_sep == '\0');

        /* Handle . and .. */
        if (namelen == 1 && comp[0] == '.') {
            /* Current directory - no change */
            if (is_last) {
                if (parent_inum_out)
                    *parent_inum_out = parent_inum;
                if (name_out) {
                    name_out[0] = '.';
                    name_out[1] = '\0';
                }
                return cur_inum;
            }
            comp = next_sep;
            if (*comp == '/') comp++;
            continue;
        }

        if (namelen == 2 && comp[0] == '.' && comp[1] == '.') {
            /* Parent directory */
            inode = get_inode(cur_inum);
            if (!inode || inode->type != INODE_DIRECTORY)
                return ERROR;
            int parent_of_cur = dir_lookup(cur_inum, "..", 2, NULL);
            if (parent_of_cur <= 0)
                parent_of_cur = cur_inum; /* at root, .. == . */
            parent_inum = parent_of_cur;

            if (is_last) {
                /* Go to grandparent */
                inode = get_inode(parent_of_cur);
                if (!inode)
                    return ERROR;
                int grandparent = dir_lookup(parent_of_cur, "..", 2, NULL);
                if (grandparent <= 0)
                    grandparent = parent_of_cur;
                if (parent_inum_out)
                    *parent_inum_out = grandparent;
                if (name_out) {
                    name_out[0] = '.';
                    name_out[1] = '.';
                    name_out[2] = '\0';
                }
                cur_inum = parent_of_cur;
                return cur_inum;
            }
            cur_inum = parent_of_cur;
            comp = next_sep;
            if (*comp == '/') comp++;
            continue;
        }

        /* Look up this component in cur_inum directory */
        inode = get_inode(cur_inum);
        if (!inode || inode->type != INODE_DIRECTORY)
            return ERROR;

        parent_inum = cur_inum;
        next_inum = dir_lookup(cur_inum, comp, namelen, NULL);

        if (is_last) {
            /* Last component */
            if (parent_inum_out)
                *parent_inum_out = cur_inum;
            if (name_out) {
                int copy_len = namelen < DIRNAMELEN ? namelen : DIRNAMELEN;
                memcpy(name_out, comp, copy_len);
                name_out[copy_len] = '\0';
            }

            if (next_inum <= 0) {
                return 0; /* not found */
            }

            /* Check for symlink on last component */
            if (follow_last) {
                inode = get_inode(next_inum);
                if (inode && inode->type == INODE_SYMLINK) {
                    /* Follow symlink */
                    symlink_len = inode->size;
                    if (symlink_len >= MAXPATHNAMELEN)
                        return ERROR;
                    if (file_read_data(next_inum, 0, symlink_buf, symlink_len) != symlink_len)
                        return ERROR;
                    symlink_buf[symlink_len] = '\0';
                    int sym_cwd = (symlink_buf[0] == '/') ? ROOTINODE : cur_inum;
                    return resolve_path_sym(symlink_buf, sym_cwd, follow_last,
                                            parent_inum_out, name_out, depth + 1);
                }
            }
            return next_inum;
        }

        /* Not last component: must exist and be a directory (or symlink to dir) */
        if (next_inum <= 0)
            return ERROR;

        inode = get_inode(next_inum);
        if (!inode)
            return ERROR;

        if (inode->type == INODE_SYMLINK) {
            /* Follow symlink in middle of path */
            symlink_len = inode->size;
            if (symlink_len >= MAXPATHNAMELEN)
                return ERROR;
            if (file_read_data(next_inum, 0, symlink_buf, symlink_len) != symlink_len)
                return ERROR;
            symlink_buf[symlink_len] = '\0';
            /* Append remaining path after the symlink */
            char rest_path[MAXPATHNAMELEN + 1];
            int rest_len = (int)strlen(next_sep);
            if (rest_len > 0) {
                if (symlink_len + rest_len + 1 >= MAXPATHNAMELEN)
                    return ERROR;
                snprintf(rest_path, sizeof(rest_path), "%s%s", symlink_buf, next_sep);
            } else {
                strncpy(rest_path, symlink_buf, MAXPATHNAMELEN);
                rest_path[MAXPATHNAMELEN] = '\0';
            }
            int sym_cwd = (symlink_buf[0] == '/') ? ROOTINODE : cur_inum;
            return resolve_path_sym(rest_path, sym_cwd, follow_last,
                                    parent_inum_out, name_out, depth + 1);
        }

        if (inode->type != INODE_DIRECTORY)
            return ERROR;

        cur_inum = next_inum;
        comp = next_sep;
        if (*comp == '/') comp++;
    }

    /* Should not reach here in normal flow */
    if (parent_inum_out)
        *parent_inum_out = parent_inum;
    if (name_out)
        name_out[0] = '\0';
    return cur_inum;
}

static int
resolve_path(const char *pathname, int cwd_inum, int follow_last,
             int *parent_inum_out, char name_out[])
{
    return resolve_path_sym(pathname, cwd_inum, follow_last, parent_inum_out, name_out, 0);
}

/* ============================================================
 * Client state management
 * ============================================================ */

static int
get_client_cwd(int pid)
{
    int i;
    for (i = 0; i < g_num_clients; i++) {
        if (g_clients[i].pid == pid)
            return g_clients[i].cwd_inum;
    }
    /* New client */
    if (g_num_clients < MAX_CLIENTS) {
        g_clients[g_num_clients].pid = pid;
        g_clients[g_num_clients].cwd_inum = ROOTINODE;
        g_num_clients++;
    }
    return ROOTINODE;
}

static void
set_client_cwd(int pid, int cwd_inum)
{
    int i;
    for (i = 0; i < g_num_clients; i++) {
        if (g_clients[i].pid == pid) {
            g_clients[i].cwd_inum = cwd_inum;
            return;
        }
    }
    /* Add new client */
    if (g_num_clients < MAX_CLIENTS) {
        g_clients[g_num_clients].pid = pid;
        g_clients[g_num_clients].cwd_inum = cwd_inum;
        g_num_clients++;
    }
}

/* ============================================================
 * Open file table management
 * ============================================================ */

/*
 * Allocate a new file descriptor for the given pid/inum.
 * Returns the fd (lowest available 0..MAX_OPEN_FILES-1), or ERROR.
 */
static int
alloc_fd(int pid, int inum, int reuse)
{
    int fd, i, slot;

    /* Find lowest unused fd for this pid */
    for (fd = 0; fd < MAX_OPEN_FILES; fd++) {
        int found = 0;
        for (i = 0; i < MAX_OPEN_TOTAL; i++) {
            if (g_open_table[i].in_use && g_open_table[i].pid == pid
                && g_open_table[i].fd == fd) {
                found = 1;
                break;
            }
        }
        if (!found) {
            /* fd is free, find an open slot in the table */
            slot = -1;
            for (i = 0; i < MAX_OPEN_TOTAL; i++) {
                if (!g_open_table[i].in_use) {
                    slot = i;
                    break;
                }
            }
            if (slot < 0)
                return ERROR; /* table full */
            g_open_table[slot].in_use = 1;
            g_open_table[slot].pid = pid;
            g_open_table[slot].fd = fd;
            g_open_table[slot].inum = inum;
            g_open_table[slot].reuse = reuse;
            g_open_table[slot].pos = 0;
            return fd;
        }
    }
    return ERROR; /* too many open files */
}

/* Find the open table index for (pid, fd). Returns -1 if not found. */
static int
find_open(int pid, int fd)
{
    int i;
    if (fd < 0 || fd >= MAX_OPEN_FILES)
        return -1;
    for (i = 0; i < MAX_OPEN_TOTAL; i++) {
        if (g_open_table[i].in_use && g_open_table[i].pid == pid
            && g_open_table[i].fd == fd) {
            return i;
        }
    }
    return -1;
}

static void
close_fd(int pid, int fd)
{
    int i = find_open(pid, fd);
    if (i >= 0)
        g_open_table[i].in_use = 0;
}

/* ============================================================
 * Validation helpers
 * ============================================================ */

/*
 * Validate a pathname argument: not NULL, not empty, not too long.
 * Returns 0 if valid, -1 if invalid.
 */
static int
valid_pathname(const void *ptr)
{
    const char *s = (const char *)ptr;
    if (!s)
        return -1;
    if (s[0] == '\0')
        return -1;
    return 0;
}

/* ============================================================
 * Filesystem operation handlers
 * ============================================================ */

static int
handle_open(int pid, int cwd_inum, const char *pathname)
{
    int inum;
    struct inode *inode;
    int fd;

    if (!pathname || pathname[0] == '\0')
        return ERROR;

    inum = resolve_path(pathname, cwd_inum, 1, NULL, NULL);
    if (inum <= 0)
        return ERROR;

    inode = get_inode(inum);
    if (!inode)
        return ERROR;

    if (inode->type == INODE_FREE)
        return ERROR;

    fd = alloc_fd(pid, inum, inode->reuse);
    if (fd == ERROR)
        return ERROR;

    return fd;
}

static int
handle_close(int pid, int fd)
{
    int idx = find_open(pid, fd);
    if (idx < 0)
        return ERROR;
    close_fd(pid, fd);
    return 0;
}

static int
handle_create(int pid, int cwd_inum, const char *pathname)
{
    int parent_inum, inum, fd;
    char name[DIRNAMELEN + 1];
    struct inode *inode;
    int namelen;

    if (!pathname || pathname[0] == '\0')
        return ERROR;

    /* Reject creating "." ".." "/" */
    {
        const char *p = pathname;
        /* strip leading slashes */
        while (*p == '/') p++;
        if (*p == '\0') return ERROR; /* just "/" */
        /* Check if the final component is "." or ".." */
        const char *last = p;
        while (*p) { if (*p == '/') last = p + 1; p++; }
        if (strcmp(last, ".") == 0 || strcmp(last, "..") == 0)
            return ERROR;
    }

    /* Try to resolve - might not exist yet */
    parent_inum = 0;
    name[0] = '\0';
    inum = resolve_path(pathname, cwd_inum, 0, &parent_inum, name);
    /* inum == 0 means not found (name & parent_inum set) */
    /* inum == ERROR means parent doesn't exist */

    if (inum == ERROR)
        return ERROR;

    if (parent_inum <= 0)
        return ERROR;

    namelen = (int)strlen(name);
    if (namelen == 0 || namelen > DIRNAMELEN)
        return ERROR;

    if (inum > 0) {
        /* File exists */
        inode = get_inode(inum);
        if (!inode)
            return ERROR;
        if (inode->type == INODE_DIRECTORY)
            return ERROR; /* can't create over a directory */
        if (inode->type == INODE_SYMLINK)
            return ERROR; /* can't create over a symlink */
        /* Truncate existing file */
        file_truncate(inum);
        inode = get_inode(inum);
        if (!inode)
            return ERROR;
        /* Keep same inode, just reset */
    } else {
        /* Create new inode */
        inum = alloc_inode(INODE_REGULAR);
        if (inum == ERROR)
            return ERROR;

        /* Add entry to parent directory */
        if (dir_add_entry(parent_inum, name, namelen, inum) < 0) {
            free_inode_and_blocks(inum);
            return ERROR;
        }

        inode = get_inode(inum);
        if (!inode)
            return ERROR;
        inode->nlink = 1;
        mark_inode_dirty(inum);
    }

    fd = alloc_fd(pid, inum, inode->reuse);
    if (fd == ERROR)
        return ERROR;

    return fd;
}

static int
handle_read(int pid, int fd, void *buf_addr, int len)
{
    int idx, inum, pos, nread;
    struct inode *inode;
    char local_buf[BLOCKSIZE];
    int total_read, chunk;
    char *dst = (char *)buf_addr;

    idx = find_open(pid, fd);
    if (idx < 0)
        return ERROR;

    inum = g_open_table[idx].inum;
    pos = g_open_table[idx].pos;

    inode = get_inode(inum);
    if (!inode || inode->type == INODE_FREE)
        return ERROR;

    /* Directories can be read but not written */
    if (len <= 0)
        return 0;

    if (inode->type == INODE_REGULAR || inode->type == INODE_DIRECTORY) {
        if (pos >= inode->size)
            return 0;
    }

    /* Read in chunks and CopyTo client */
    total_read = 0;
    while (len > 0) {
        chunk = len < BLOCKSIZE ? len : BLOCKSIZE;
        nread = file_read_data(inum, pos, local_buf, chunk);
        if (nread <= 0)
            break;
        if (CopyTo(pid, (char *)dst + total_read, local_buf, nread) != 0)
            return ERROR;
        total_read += nread;
        pos += nread;
        len -= nread;
        if (nread < chunk)
            break; /* EOF */
    }

    g_open_table[idx].pos = pos;
    return total_read;
}

static int
handle_write(int pid, int fd, const void *buf_addr, int len)
{
    int idx, inum, pos, nwritten;
    struct inode *inode;
    char local_buf[BLOCKSIZE];
    int total_written, chunk;
    const char *src = (const char *)buf_addr;

    idx = find_open(pid, fd);
    if (idx < 0)
        return ERROR;

    inum = g_open_table[idx].inum;
    pos = g_open_table[idx].pos;

    inode = get_inode(inum);
    if (!inode || inode->type == INODE_FREE)
        return ERROR;

    /* Can't write to directories */
    if (inode->type == INODE_DIRECTORY)
        return ERROR;

    if (len <= 0)
        return 0;

    /* Write in chunks, CopyFrom client */
    total_written = 0;
    while (len > 0) {
        chunk = len < BLOCKSIZE ? len : BLOCKSIZE;
        if (CopyFrom(pid, local_buf, (char *)src + total_written, chunk) != 0)
            return ERROR;
        nwritten = file_write_data(inum, pos, local_buf, chunk);
        if (nwritten <= 0)
            break;
        total_written += nwritten;
        pos += nwritten;
        len -= nwritten;
    }

    g_open_table[idx].pos = pos;
    return total_written;
}

static int
handle_seek(int pid, int fd, int offset, int whence)
{
    int idx, inum, pos, new_pos;
    struct inode *inode;

    idx = find_open(pid, fd);
    if (idx < 0)
        return ERROR;

    inum = g_open_table[idx].inum;
    pos = g_open_table[idx].pos;

    inode = get_inode(inum);
    if (!inode || inode->type == INODE_FREE)
        return ERROR;

    switch (whence) {
    case SEEK_SET:
        new_pos = offset;
        break;
    case SEEK_CUR:
        new_pos = pos + offset;
        break;
    case SEEK_END:
        new_pos = inode->size + offset;
        break;
    default:
        return ERROR;
    }

    if (new_pos < 0)
        return ERROR;

    g_open_table[idx].pos = new_pos;
    return new_pos;
}

static int
handle_link(int pid, int cwd_inum, const char *oldname, const char *newname)
{
    int old_inum, new_parent_inum, existing_inum;
    char new_name[DIRNAMELEN + 1];
    struct inode *old_inode;
    int namelen;

    (void)pid;

    if (!oldname || !newname)
        return ERROR;

    old_inum = resolve_path(oldname, cwd_inum, 1, NULL, NULL);
    if (old_inum <= 0)
        return ERROR;

    old_inode = get_inode(old_inum);
    if (!old_inode)
        return ERROR;

    /* Cannot link to directories */
    if (old_inode->type == INODE_DIRECTORY)
        return ERROR;

    new_name[0] = '\0';
    existing_inum = resolve_path(newname, cwd_inum, 0, &new_parent_inum, new_name);

    if (existing_inum == ERROR)
        return ERROR; /* parent doesn't exist */
    if (existing_inum > 0)
        return ERROR; /* new name already exists */
    if (new_parent_inum <= 0)
        return ERROR;

    namelen = (int)strlen(new_name);
    if (namelen == 0 || namelen > DIRNAMELEN)
        return ERROR;

    if (dir_add_entry(new_parent_inum, new_name, namelen, old_inum) < 0)
        return ERROR;

    /* Increment nlink */
    old_inode = get_inode(old_inum);
    if (!old_inode)
        return ERROR;
    old_inode->nlink++;
    mark_inode_dirty(old_inum);

    return 0;
}

static int
handle_unlink(int pid, int cwd_inum, const char *pathname)
{
    int parent_inum, inum;
    char name[DIRNAMELEN + 1];
    struct inode *inode;
    int namelen;

    (void)pid;

    if (!pathname || pathname[0] == '\0')
        return ERROR;

    name[0] = '\0';
    inum = resolve_path(pathname, cwd_inum, 0, &parent_inum, name);
    if (inum <= 0)
        return ERROR;
    if (parent_inum <= 0)
        return ERROR;

    inode = get_inode(inum);
    if (!inode)
        return ERROR;

    if (inode->type == INODE_DIRECTORY)
        return ERROR; /* cannot unlink directories */

    namelen = (int)strlen(name);
    if (namelen == 0)
        return ERROR;

    /* Remove directory entry */
    if (dir_remove_entry(parent_inum, name, namelen) < 0)
        return ERROR;

    /* Decrement nlink */
    inode = get_inode(inum);
    if (!inode)
        return ERROR;
    inode->nlink--;
    mark_inode_dirty(inum);

    if (inode->nlink <= 0) {
        /* Free inode and blocks */
        free_inode_and_blocks(inum);
    }

    return 0;
}

static int
handle_symlink(int pid, int cwd_inum, const char *oldname, const char *newname)
{
    int new_parent_inum, existing_inum, link_inum;
    char new_name[DIRNAMELEN + 1];
    struct inode *link_inode;
    int namelen, link_len;

    (void)pid;

    if (!oldname || !newname)
        return ERROR;

    new_name[0] = '\0';
    existing_inum = resolve_path(newname, cwd_inum, 0, &new_parent_inum, new_name);

    if (existing_inum == ERROR)
        return ERROR; /* parent doesn't exist */
    if (existing_inum > 0)
        return ERROR; /* new name already exists */
    if (new_parent_inum <= 0)
        return ERROR;

    namelen = (int)strlen(new_name);
    if (namelen == 0 || namelen > DIRNAMELEN)
        return ERROR;

    /* Create symlink inode */
    link_inum = alloc_inode(INODE_SYMLINK);
    if (link_inum == ERROR)
        return ERROR;

    link_inode = get_inode(link_inum);
    if (!link_inode) {
        free_inode_and_blocks(link_inum);
        return ERROR;
    }
    link_inode->nlink = 1;
    mark_inode_dirty(link_inum);

    /* Write the target pathname as symlink data (no null terminator) */
    link_len = (int)strlen(oldname);
    if (link_len > 0) {
        if (file_write_data(link_inum, 0, oldname, link_len) != link_len) {
            free_inode_and_blocks(link_inum);
            return ERROR;
        }
    }

    /* Update size */
    link_inode = get_inode(link_inum);
    if (!link_inode) {
        free_inode_and_blocks(link_inum);
        return ERROR;
    }
    link_inode->size = link_len;
    mark_inode_dirty(link_inum);

    /* Add entry to parent directory */
    if (dir_add_entry(new_parent_inum, new_name, namelen, link_inum) < 0) {
        free_inode_and_blocks(link_inum);
        return ERROR;
    }

    return 0;
}

static int
handle_readlink(int pid, int cwd_inum, const char *pathname, void *buf_addr, int len)
{
    int inum;
    struct inode *inode;
    int link_len, read_len;
    char local_buf[MAXPATHNAMELEN + 1];

    if (!pathname || !buf_addr)
        return ERROR;

    /* Don't follow the symlink itself */
    inum = resolve_path(pathname, cwd_inum, 0, NULL, NULL);
    if (inum <= 0)
        return ERROR;

    inode = get_inode(inum);
    if (!inode || inode->type != INODE_SYMLINK)
        return ERROR;

    link_len = inode->size;
    read_len = link_len < len ? link_len : len;

    if (read_len > 0) {
        if (file_read_data(inum, 0, local_buf, read_len) != read_len)
            return ERROR;
        if (CopyTo(pid, buf_addr, local_buf, read_len) != 0)
            return ERROR;
    }

    return read_len;
}

static int
handle_mkdir(int pid, int cwd_inum, const char *pathname)
{
    int parent_inum, existing_inum, new_inum;
    char name[DIRNAMELEN + 1];
    struct inode *new_inode;
    struct dir_entry entries[2];
    int namelen;

    (void)pid;

    if (!pathname || pathname[0] == '\0')
        return ERROR;

    /* Reject "." ".." "/" */
    {
        const char *p = pathname;
        while (*p == '/') p++;
        if (*p == '\0') return ERROR;
        const char *last = p;
        while (*p) { if (*p == '/') last = p + 1; p++; }
        if (strcmp(last, ".") == 0 || strcmp(last, "..") == 0)
            return ERROR;
    }

    name[0] = '\0';
    existing_inum = resolve_path(pathname, cwd_inum, 0, &parent_inum, name);

    if (existing_inum == ERROR)
        return ERROR;
    if (existing_inum > 0)
        return ERROR; /* already exists */
    if (parent_inum <= 0)
        return ERROR;

    namelen = (int)strlen(name);
    if (namelen == 0 || namelen > DIRNAMELEN)
        return ERROR;

    /* Allocate new directory inode */
    new_inum = alloc_inode(INODE_DIRECTORY);
    if (new_inum == ERROR)
        return ERROR;

    new_inode = get_inode(new_inum);
    if (!new_inode) {
        free_inode_and_blocks(new_inum);
        return ERROR;
    }
    new_inode->nlink = 2; /* for "." and name in parent */
    mark_inode_dirty(new_inum);

    /* Write . and .. entries */
    memset(entries, 0, sizeof(entries));
    entries[0].inum = (short)new_inum;
    entries[0].name[0] = '.';
    entries[1].inum = (short)parent_inum;
    entries[1].name[0] = '.';
    entries[1].name[1] = '.';

    if (file_write_data(new_inum, 0, (char *)entries, sizeof(entries)) != (int)sizeof(entries)) {
        free_inode_and_blocks(new_inum);
        return ERROR;
    }

    new_inode = get_inode(new_inum);
    if (!new_inode) {
        free_inode_and_blocks(new_inum);
        return ERROR;
    }
    new_inode->size = 2 * sizeof(struct dir_entry);
    mark_inode_dirty(new_inum);

    /* Add entry to parent directory */
    if (dir_add_entry(parent_inum, name, namelen, new_inum) < 0) {
        free_inode_and_blocks(new_inum);
        return ERROR;
    }

    return 0;
}

static int
handle_rmdir(int pid, int cwd_inum, const char *pathname)
{
    int parent_inum, inum;
    char name[DIRNAMELEN + 1];
    struct inode *inode;
    int namelen;

    (void)pid;

    if (!pathname || pathname[0] == '\0')
        return ERROR;

    /* Reject "." ".." "/" */
    {
        const char *p = pathname;
        while (*p == '/') p++;
        if (*p == '\0') return ERROR; /* trying to rmdir root */
        const char *last = p;
        while (*p) { if (*p == '/') last = p + 1; p++; }
        if (strcmp(last, ".") == 0 || strcmp(last, "..") == 0)
            return ERROR;
    }

    name[0] = '\0';
    inum = resolve_path(pathname, cwd_inum, 0, &parent_inum, name);
    if (inum <= 0)
        return ERROR;
    if (parent_inum <= 0)
        return ERROR;

    /* Cannot remove root */
    if (inum == ROOTINODE)
        return ERROR;

    inode = get_inode(inum);
    if (!inode || inode->type != INODE_DIRECTORY)
        return ERROR;

    if (!dir_is_empty(inum))
        return ERROR;

    namelen = (int)strlen(name);
    if (namelen == 0)
        return ERROR;

    /* Remove entry from parent */
    if (dir_remove_entry(parent_inum, name, namelen) < 0)
        return ERROR;

    /* Free inode and blocks */
    free_inode_and_blocks(inum);

    return 0;
}

static int
handle_chdir(int pid, int cwd_inum, const char *pathname)
{
    int inum;
    struct inode *inode;

    if (!pathname || pathname[0] == '\0')
        return ERROR;

    inum = resolve_path(pathname, cwd_inum, 1, NULL, NULL);
    if (inum <= 0)
        return ERROR;

    inode = get_inode(inum);
    if (!inode || inode->type != INODE_DIRECTORY)
        return ERROR;

    set_client_cwd(pid, inum);
    return 0;
}

static int
handle_stat(int pid, int cwd_inum, const char *pathname, void *stat_addr)
{
    int inum;
    struct inode *inode;
    struct Stat sb;

    if (!pathname || !stat_addr)
        return ERROR;

    inum = resolve_path(pathname, cwd_inum, 1, NULL, NULL);
    if (inum <= 0)
        return ERROR;

    inode = get_inode(inum);
    if (!inode || inode->type == INODE_FREE)
        return ERROR;

    sb.inum = inum;
    sb.type = inode->type;
    sb.size = inode->size;
    sb.nlink = inode->nlink;

    if (CopyTo(pid, stat_addr, &sb, sizeof(sb)) != 0)
        return ERROR;

    return 0;
}

/* ============================================================
 * Initialization
 * ============================================================ */

static void
init_fs(void)
{
    char buf[SECTORSIZE];
    struct fs_header *hdr;
    int i, inode_blocks, max_data_blocks;
    struct inode *inode;
    char *ind_blk;
    int *ind_entries;
    char *used_blocks;

    /* Read super block */
    if (ReadSector(1, buf) != 0) {
        Exit(1);
    }

    hdr = (struct fs_header *)buf;
    g_num_blocks = hdr->num_blocks;
    g_num_inodes = hdr->num_inodes;

    /* Calculate first data block */
    inode_blocks = (g_num_inodes + INODES_PER_BLOCK) / INODES_PER_BLOCK;
    g_first_data_block = 1 + inode_blocks;

    /* Allocate free block array */
    max_data_blocks = g_num_blocks - g_first_data_block;
    if (max_data_blocks < 0) max_data_blocks = 0;
    g_free_blocks = (int *)malloc(max_data_blocks * sizeof(int));
    g_free_block_count = 0;

    /* Allocate free inode array */
    g_free_inodes = (int *)malloc(g_num_inodes * sizeof(int));
    g_free_inode_count = 0;

    /* Track which data blocks are in use */
    used_blocks = (char *)calloc(g_num_blocks, 1);

    /* Scan inodes to build free lists */
    for (i = 1; i <= g_num_inodes; i++) {
        inode = get_inode(i);
        if (!inode)
            continue;

        if (inode->type == INODE_FREE) {
            /* Add to free inode list */
            g_free_inodes[g_free_inode_count++] = i;
        } else {
            int j;
            /* Mark used blocks */
            for (j = 0; j < NUM_DIRECT; j++) {
                if (inode->direct[j] != 0 && inode->direct[j] < g_num_blocks) {
                    used_blocks[inode->direct[j]] = 1;
                }
            }
            if (inode->indirect != 0 && inode->indirect < g_num_blocks) {
                used_blocks[inode->indirect] = 1;
                ind_blk = get_block(inode->indirect);
                if (ind_blk) {
                    ind_entries = (int *)ind_blk;
                    for (j = 0; j < PTRS_PER_BLOCK; j++) {
                        if (ind_entries[j] != 0 && ind_entries[j] < g_num_blocks) {
                            used_blocks[ind_entries[j]] = 1;
                        }
                    }
                }
            }
        }
    }

    /* Build free block list (scan ascending so pop gives highest first) */
    for (i = g_first_data_block; i < g_num_blocks; i++) {
        if (!used_blocks[i]) {
            g_free_blocks[g_free_block_count++] = i;
        }
    }

    free(used_blocks);
}

/* ============================================================
 * Main
 * ============================================================ */

int
main(void)
{
    struct yfs_msg msg;
    int pid;
    int cwd_inum;
    char path_buf[MAXPATHNAMELEN + 1];
    char path_buf2[MAXPATHNAMELEN + 1];
    int retval;

    /* Register as file server */
    if (Register(FILE_SERVER) != 0) {
        Exit(1);
    }

    /* Initialize file system */
    init_fs();

    /* Main receive loop */
    while (1) {
        pid = Receive(&msg);

        if (pid == 0) {
            /* Deadlock prevention: all other processes are blocked */
            /* Just continue waiting */
            continue;
        }
        if (pid == ERROR) {
            continue;
        }

        cwd_inum = get_client_cwd(pid);
        retval = ERROR;

        switch (msg.type) {

        case MSG_OPEN:
            if (msg.ptr1) {
                if (CopyFrom(pid, path_buf, msg.ptr1, MAXPATHNAMELEN) == 0) {
                    path_buf[MAXPATHNAMELEN] = '\0';
                    if (valid_pathname(path_buf) == 0)
                        retval = handle_open(pid, cwd_inum, path_buf);
                }
            }
            break;

        case MSG_CLOSE:
            retval = handle_close(pid, msg.arg1);
            break;

        case MSG_CREATE:
            if (msg.ptr1) {
                if (CopyFrom(pid, path_buf, msg.ptr1, MAXPATHNAMELEN) == 0) {
                    path_buf[MAXPATHNAMELEN] = '\0';
                    if (valid_pathname(path_buf) == 0)
                        retval = handle_create(pid, cwd_inum, path_buf);
                }
            }
            break;

        case MSG_READ:
            retval = handle_read(pid, msg.arg1, msg.ptr1, msg.arg2);
            break;

        case MSG_WRITE:
            retval = handle_write(pid, msg.arg1, msg.ptr1, msg.arg2);
            break;

        case MSG_SEEK:
            retval = handle_seek(pid, msg.arg1, msg.arg2, msg.arg3);
            break;

        case MSG_LINK:
            if (msg.ptr1 && msg.ptr2) {
                if (CopyFrom(pid, path_buf, msg.ptr1, MAXPATHNAMELEN) == 0 &&
                    CopyFrom(pid, path_buf2, msg.ptr2, MAXPATHNAMELEN) == 0) {
                    path_buf[MAXPATHNAMELEN] = '\0';
                    path_buf2[MAXPATHNAMELEN] = '\0';
                    retval = handle_link(pid, cwd_inum, path_buf, path_buf2);
                }
            }
            break;

        case MSG_UNLINK:
            if (msg.ptr1) {
                if (CopyFrom(pid, path_buf, msg.ptr1, MAXPATHNAMELEN) == 0) {
                    path_buf[MAXPATHNAMELEN] = '\0';
                    if (valid_pathname(path_buf) == 0)
                        retval = handle_unlink(pid, cwd_inum, path_buf);
                }
            }
            break;

        case MSG_SYMLINK:
            if (msg.ptr1 && msg.ptr2) {
                if (CopyFrom(pid, path_buf, msg.ptr1, MAXPATHNAMELEN) == 0 &&
                    CopyFrom(pid, path_buf2, msg.ptr2, MAXPATHNAMELEN) == 0) {
                    path_buf[MAXPATHNAMELEN] = '\0';
                    path_buf2[MAXPATHNAMELEN] = '\0';
                    retval = handle_symlink(pid, cwd_inum, path_buf, path_buf2);
                }
            }
            break;

        case MSG_READLINK:
            if (msg.ptr1) {
                if (CopyFrom(pid, path_buf, msg.ptr1, MAXPATHNAMELEN) == 0) {
                    path_buf[MAXPATHNAMELEN] = '\0';
                    if (valid_pathname(path_buf) == 0)
                        retval = handle_readlink(pid, cwd_inum, path_buf,
                                                 msg.ptr2, msg.arg1);
                }
            }
            break;

        case MSG_MKDIR:
            if (msg.ptr1) {
                if (CopyFrom(pid, path_buf, msg.ptr1, MAXPATHNAMELEN) == 0) {
                    path_buf[MAXPATHNAMELEN] = '\0';
                    if (valid_pathname(path_buf) == 0)
                        retval = handle_mkdir(pid, cwd_inum, path_buf);
                }
            }
            break;

        case MSG_RMDIR:
            if (msg.ptr1) {
                if (CopyFrom(pid, path_buf, msg.ptr1, MAXPATHNAMELEN) == 0) {
                    path_buf[MAXPATHNAMELEN] = '\0';
                    if (valid_pathname(path_buf) == 0)
                        retval = handle_rmdir(pid, cwd_inum, path_buf);
                }
            }
            break;

        case MSG_CHDIR:
            if (msg.ptr1) {
                if (CopyFrom(pid, path_buf, msg.ptr1, MAXPATHNAMELEN) == 0) {
                    path_buf[MAXPATHNAMELEN] = '\0';
                    if (valid_pathname(path_buf) == 0)
                        retval = handle_chdir(pid, cwd_inum, path_buf);
                }
            }
            break;

        case MSG_STAT:
            if (msg.ptr1) {
                if (CopyFrom(pid, path_buf, msg.ptr1, MAXPATHNAMELEN) == 0) {
                    path_buf[MAXPATHNAMELEN] = '\0';
                    if (valid_pathname(path_buf) == 0)
                        retval = handle_stat(pid, cwd_inum, path_buf, msg.ptr2);
                }
            }
            break;

        case MSG_SYNC:
            sync_all();
            retval = 0;
            break;

        case MSG_SHUTDOWN:
            sync_all();
            msg.arg1 = 0;
            Reply(&msg, pid);
            Exit(0);
            break;

        default:
            retval = ERROR;
            break;
        }

        msg.arg1 = retval;
        Reply(&msg, pid);
    }

    return 0;
}
